const n=JSON.parse('{"key":"v-c505ff26","path":"/project/%E5%8C%85%E7%AE%A1%E7%90%86%E5%B7%A5%E5%85%B7%E4%BB%A5%E5%8F%8A%E5%A4%9A%E5%8C%85%E7%AE%A1%E7%90%86.html","title":"包管理工具以及多包管理","lang":"zh-CN","frontmatter":{"title":"包管理工具以及多包管理","isTimeLine":true,"date":"2025-12-15T00:00:00.000Z","category":["前端"],"tag":["JavaScript","源码"]},"headers":[{"level":3,"title":"npm与yarn","slug":"npm与yarn","link":"#npm与yarn","children":[]},{"level":3,"title":"cnpm、npx和pnpm的区别","slug":"cnpm、npx和pnpm的区别","link":"#cnpm、npx和pnpm的区别","children":[]},{"level":3,"title":"多包管理","slug":"多包管理","link":"#多包管理","children":[]},{"level":3,"title":"优雅的提交","slug":"优雅的提交","link":"#优雅的提交","children":[]}],"git":{"createdTime":1773458982000,"updatedTime":1773458982000,"contributors":[{"name":"liunal","email":"liunal","commits":1}]},"readingTime":{"minutes":5.82,"words":1746},"filePathRelative":"project/包管理工具以及多包管理.md","localizedDate":"2025年12月15日","excerpt":"<h3> npm与yarn</h3>\\n<ol>\\n<li>npm早期\\n<ul>\\n<li>npm在安装依赖有层级嵌套问题,如包A有依赖B,那么B安装在A的<code>node_modules</code>文件夹中，B可能也有自己的依赖包C,那么会出现依赖递归或依赖重复下载问题。</li>\\n<li>依赖包会出现重复,出现体积过大，内存浪费-&gt;目录层级过深,导致文件路径过长,会出现删除不掉的情况或不好调试的问题。</li>\\n</ul>\\n</li>\\n<li>yarn\\n<ul>\\n<li>出现是为了解决问题：npm还没有<code>package-lock.json</code>文件,安装的时候速度很慢,稳定性很差，下载速度慢。</li>\\n<li>确定性: 通过yarn.lock；这个文件的依赖版本号不是固定的，结构非json结构，而是一种自定义的标记模式。</li>\\n<li>扁平化：安装依赖为模块扁平化方式；将不同版本的依赖包，安装一定的策略归结为单个版本。</li>\\n<li>网络性能更好：yarn采用了请求排队的理念,类似于并发池连接；</li>\\n<li>采用缓存机制：实现了离线模式</li>\\n</ul>\\n</li>\\n<li>npm和yarn的区别是什么？\\n<ul>\\n<li>yarn是为了弥补npm下载速度慢、版本一致性的问题而产生的。在npm5.4.2版本后，因为竞争关系，他们都支持缓存、扁平化、包并行下载，速度都有明显提升。所有现在的npm和yarn都能选择，他们的性能、优化、缓存都差不多。</li>\\n<li>不同的是npm是<code>package-lock.json</code>采用的是JSON的结构，依赖是固定的版本；Yarn是<code>yarn-lock.json</code>，结构是一种自定义的标记方式，子依赖的版本不是固定的版本。</li>\\n</ul>\\n</li>\\n<li>转换:<code>package-lock.json</code>与<code>yarn-lock.json</code>的转换有一个专门的工具<code>synp</code>。</li>\\n<li>缺点:解决了嵌套方式的部分问题，但是引入了幽灵依赖的问题，并且同名的包只会提升一个版本的，其余的版本依然会复制多次。</li>\\n</ol>"}');export{n as data};
